# Dockerfile.map
# homefront-map: separate Cloud Run service for the map page + polygon API
# Same base image as the alert relay for consistent Node.js version.
# min-instances=0 (scale-to-zero) — this is NOT the always-on polling service.

FROM node:20-alpine

RUN mkdir -p /usr/src/app && chown node:node /usr/src/app
WORKDIR /usr/src/app

USER node

COPY --chown=node:node package*.json ./

# Install production dependencies (includes turf, adm-zip, concaveman)
RUN npm install --omit=dev

COPY --chown=node:node . .

ENV PORT 8080
EXPOSE 8080

# Different entry point from the alert relay
CMD [ "node", "map-server.js" ]
